{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMFb5IX5LVidUkjsKW++19s"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":null,"metadata":{"id":"wYBWZ_XflfDj"},"outputs":[],"source":["from fastapi import FastAPI, UploadFile, File\n","import tensorflow as tf\n","import numpy as np\n","from PIL import Image\n","from tensorflow.keras.applications.efficientnet import preprocess_input\n","import os\n","import gdown\n","\n","MODEL_PATH = \"best_eff_banana.keras\"\n","\n","if not os.path.exists(MODEL_PATH):\n","    gdown.download(\n","        \"https://drive.google.com/uc?id=17FGbIA9-WGV9S-SQOnbRj9hBbL5qN9Gl\",\n","        MODEL_PATH,\n","        quiet=False\n","    )\n","\n","app = FastAPI(\n","    title=\"Banana Disease Classification API\"\n",")\n","\n","model = tf.keras.models.load_model(MODEL_PATH)\n","\n","classes = [\n","    \"cordana\",\n","    \"healthy\",\n","    \"pestalotiopsis\",\n","    \"sigatoka\"\n","]\n","\n","@app.get(\"/\")\n","def home():\n","    return {\n","        \"status\": \"active\",\n","        \"message\": \"Banana Disease API Ready\",\n","        \"model\": \"EfficientNetB0\"\n","    }\n","\n","@app.post(\"/predict\")\n","async def predict(file: UploadFile = File(...)):\n","\n","    img = Image.open(file.file).convert(\"RGB\")\n","    img = img.resize((224,224))\n","\n","    x = np.array(img)\n","    x = np.expand_dims(x, axis=0)\n","    x = preprocess_input(x)\n","\n","    pred = model.predict(x, verbose=0)\n","\n","    idx = int(np.argmax(pred))\n","\n","    return {\n","        \"class\": classes[idx],\n","        \"confidence\": float(np.max(pred)*100),\n","        \"progress\": float(np.max(pred))\n","    }"]}]}